package test.rice.parse;

import main.rice.node.*;
import main.rice.obj.PyIntObj;
import main.rice.parse.ConfigFile;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Test cases for the ConfigFile class.
 * Total: 1.5 points (3 tests)
 */
class ConfigFileTest {

    // Simple config file with basic types
    private static ConfigFile simpleConfig;
    private static List<APyNode<?>> simpleNodes;

    // Config file with nested types
    private static ConfigFile nestedConfig;
    private static List<APyNode<?>> nestedNodes;

    // Config file with empty nodes list
    private static ConfigFile emptyConfig;

    @BeforeAll
    static void setUp() {
        // Set up simple config with int and bool nodes
        PyIntNode intNode = new PyIntNode();
        intNode.setExDomain(Arrays.asList(1, 2, 3));
        intNode.setRanDomain(Arrays.asList(1, 2, 3, 4, 5));

        PyBoolNode boolNode = new PyBoolNode();
        boolNode.setExDomain(Arrays.asList(0, 1));
        boolNode.setRanDomain(Arrays.asList(0, 1));

        simpleNodes = Arrays.asList(intNode, boolNode);
        simpleConfig = new ConfigFile("testFunc", simpleNodes, 100);

        // Set up nested config with list of ints
        PyIntNode innerIntNode = new PyIntNode();
        innerIntNode.setExDomain(Arrays.asList(1, 2));
        innerIntNode.setRanDomain(Arrays.asList(1, 2, 3));

        PyListNode<PyIntObj> listNode = new PyListNode<>(innerIntNode);
        listNode.setExDomain(Arrays.asList(0, 1, 2));
        listNode.setRanDomain(Arrays.asList(0, 1, 2, 3));

        nestedNodes = Arrays.asList(listNode);
        nestedConfig = new ConfigFile("nestedFunc", nestedNodes, 50);

        // Set up empty config
        emptyConfig = new ConfigFile("emptyFunc", new ArrayList<>(), 0);
    }

    /**
     * Tests that getFuncName returns the correct function name.
     * (0.5 pts)
     */
    @Test
    void testGetFuncName() {
        assertEquals("testFunc", simpleConfig.getFuncName());
        assertEquals("nestedFunc", nestedConfig.getFuncName());
        assertEquals("emptyFunc", emptyConfig.getFuncName());
    }

    /**
     * Tests that getNumRand returns the correct number of random test cases.
     * (0.5 pts)
     */
}

package test.rice;

import main.rice.Main;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.io.TempDir;

import java.io.*;
import java.nio.file.*;
import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Test cases for the Main class.
 * Total: 12.0 points (6 tests)
 */
class MainTest {

    @TempDir
    Path tempDir;

    private Path configPath;
    private Path solutionPath;
    private Path implDirPath;

    @BeforeEach
    void setUp() throws IOException {
        configPath = tempDir.resolve("config.json");
        solutionPath = tempDir.resolve("solution.py");
        implDirPath = tempDir.resolve("impls");
        Files.createDirectory(implDirPath);
    }

    /**
     * Helper to create a config file.
     */
    private void createConfigFile(String content) throws IOException {
        Files.writeString(configPath, content);
    }

    /**
     * Helper to create a solution file.
     */
    private void createSolutionFile(String content) throws IOException {
        Files.writeString(solutionPath, content);
    }

    /**
     * Helper to create an implementation file.
     */
    private void createImplFile(String filename, String content) throws IOException {
        Files.writeString(implDirPath.resolve(filename), content);
    }

    /**
     * Tests that Main.generateTests works correctly when all files are valid.
     * (1.0 pts)
     */
    @Test
    void testAllFilesCorrect() throws IOException, InvalidConfigException, InterruptedException {
        // Create a simple config
        String config = """
            {
                "fname": "add_one",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 0
            }
            """;
        createConfigFile(config);

        // Create a simple solution that adds 1 to the input
        String solution = """
            def add_one(x):
                return x + 1
            """;
        createSolutionFile(solution);

        // Create a correct implementation
        createImplFile("correct.py", """
            def add_one(x):
                return x + 1
            """);

        String[] args = {
            configPath.toString(),
            solutionPath.toString(),
            implDirPath.toString()
        };

        Set<TestCase> result = Main.generateTests(args);
        // All implementations are correct, so the concise set should be empty
        // (no test cases needed to catch bugs since there are no bugs)
        assertTrue(result.isEmpty());
    }

    /**
     * Tests that Main.generateTests works correctly with only one test case.
     * (1.0 pts)
     */
    @Test
    void testOnlyOneCase() throws IOException, InvalidConfigException, InterruptedException {
        // Create a config with only one possible test case
        String config = """
            {
                "fname": "identity",
                "types": ["int"],
                "exhaustive domain": ["[1]"],
                "random domain": ["[1]"],
                "num random": 0
            }
            """;
        createConfigFile(config);

        // Create a solution
        String solution = """
            def identity(x):
                return x
            """;
        createSolutionFile(solution);

        // Create a buggy implementation
        createImplFile("buggy.py", """
            def identity(x):
                return x + 1
            """);

        String[] args = {
            configPath.toString(),
            solutionPath.toString(),
            implDirPath.toString()
        };

        Set<TestCase> result = Main.generateTests(args);
        // There's one buggy implementation, and only one test case can catch it
        assertEquals(1, result.size());
    }

    /**
     * Tests Main.generateTests with multiple test cases for non-deterministic coverage.
     * (2.0 pts)
     */
    @Test
    void testMultipleCasesNonDeterministic() throws IOException, InvalidConfigException, InterruptedException {
        // Create a config
        String config = """
            {
                "fname": "double",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 0
            }
            """;
        createConfigFile(config);

        // Create a solution
        String solution = """
            def double(x):
                return x * 2
            """;
        createSolutionFile(solution);

        // Create multiple buggy implementations that fail on different inputs
        createImplFile("buggy1.py", """
            def double(x):
                if x == 1:
                    return 0
                return x * 2
            """);

        createImplFile("buggy2.py", """
            def double(x):
                if x == 2:
                    return 0
                return x * 2
            """);

        String[] args = {
            configPath.toString(),
            solutionPath.toString(),
            implDirPath.toString()
        };

        Set<TestCase> result = Main.generateTests(args);
        // Should find a minimal set that catches both buggy implementations
        // Could be 1 or 2 test cases depending on set cover algorithm
        assertTrue(result.size() >= 1 && result.size() <= 2);
    }

    /**
     * Tests Main.generateTests with multiple test cases for deterministic coverage.
     * (2.0 pts)
     */
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class whose instances represent templates for creating Python objects. Each
 * APyNode is a generator for a type of APyObj. For instance, a PyIntNode generates
 * PyIntObjs. If this node represents a compound type, e.g. a list, it will hold
 * references to its child node(s).
 *
 * @param <ObjType> the type of Python object generated by this tree
 */
public abstract class APyNode<ObjType extends APyObj> {

    /**
     * The domain for exhaustive generation.
     */
    protected List<? extends Number> exDomain;

    /**
     * The domain for random generation.
     */
    protected List<? extends Number> ranDomain;

    /**
     * The RNG used for random generation.
     */
    protected Random rand = new Random();

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns the right child node.
     *
     * @return the right child node
     */
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Sets the exhaustive domain to the input list of numbers.
     *
     * @param domain the exhaustive domain
     */
    public void setExDomain(List<? extends Number> domain) {
        this.exDomain = domain;
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<? extends Number> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain to the input list of numbers.
     *
     * @param domain the random domain
     */
    public void setRanDomain(List<? extends Number> domain) {
        this.ranDomain = domain;
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<? extends Number> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Generates all valid PyObjs of type ObjType within the exhaustive domain.
     *
     * @return a set of PyObjs of type ObjType comprising the exhaustive domain
     */
    public abstract Set<ObjType> genExVals();

    /**
     * Generates a single valid PyObj of type ObjType within the random domain.
     *
     * @return a single PyObj of type ObjType selected from the random domain
     */
    public abstract ObjType genRandVal();

    /**
     * Makes a random choice from the random domain.
     *
     * @return a random element from the random domain
     */
    protected Number ranDomainChoice() {
        int choice = this.rand.nextInt(this.ranDomain.size());
        return this.ranDomain.get(choice);
    }

    /**
     * Finds and returns the maximum value in the exhaustive domain.
     *
     * @return the maximum value in the exhaustive domain
     */
    protected int exDomainMax() {
        var maxLength = 0;
        for (Number length : this.exDomain) {
            if (length.intValue() > maxLength) {
                // Found new max
                maxLength = length.intValue();
            }
        }
        return maxLength;
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;

import java.util.HashSet;
import java.util.Set;

/**
 * A representation of a leaf node for generating PyIntObjs.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    /**
     * Generates all valid PyIntObjs within the exhaustive domain.
     *
     * @return a set of PyIntObjs comprising the exhaustive domain
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> vals = new HashSet<>();
        for (Number value : this.exDomain) {
            vals.add(new PyIntObj(value.intValue()));
        }
        return vals;
    }

    /**
     * Generates a single valid PyIntObj within the random domain.
     *
     * @return a single PyIntObj selected from the random domain
     */
    @Override
    public PyIntObj genRandVal() {
        return new PyIntObj(this.ranDomainChoice().intValue());
    }
}

package main.rice.node;

import main.rice.obj.PyBoolObj;

import java.util.HashSet;
import java.util.Set;

/**
 * A representation of a leaf node for generating PyBoolObjs. Assumes that the domains
 * will only include 0 and/or 1.
 */
public class PyBoolNode extends APyNode<PyBoolObj> {

    /**
     * Generates all valid PyBoolObjs within the exhaustive domain. Interprets 0 (in
     * the exhaustive domain) as False and 1 as True.
     *
     * @return a set of PyBoolObjs comprising the exhaustive domain
     */
    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> vals = new HashSet<>();
        for (Number value : this.exDomain) {
            vals.add(new PyBoolObj((value.intValue() > 0)));
        }
        return vals;
    }

    /**
     * Generates a single valid PyBoolObj within the random domain.
     *
     * @return a single PyBoolObj selected from the random domain
     */
    @Override
    public PyBoolObj genRandVal() {
        return new PyBoolObj(this.ranDomainChoice().intValue() > 0);
    }
}

