/**
 * A representation of a node for generating PyDictObjs.
 *
 * @param <KeyType> the type of object generated by the leftChild node, which represents
 *                  the type of the keys in the dictionary; if we invoke
 *                  this.leftChild.genExVals(), it will return List<KeyType>
 * @param <ValType> the type of object generated by the rightChild node, which represents
 *                  the type of the values in the dictionary; if we invoke
 *                  this.leftChild.genExVals(), it will return List<ValType>
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    /**
     * Overrides the leftChild in the superclass (APyNode) with a more specific type: a
     * generator of KeyType objects.
     */
    protected APyNode<KeyType> leftChild;

    /**
     * Overrides the leftChild in the superclass (APyNode) with a more specific type: a
     * generator of ValType objects.
     */
    protected APyNode<ValType> rightChild;

    /**
     * Constructor for a PyDictNode; stores references to the keyChild (this.leftChild)
     * and valChild (this.rightChild).
     *
     * @param keyChild a node representing the valid keys for this dictionary
     * @param valChild a node representing the valid values for this dictionary
     */
    public PyDictNode(APyNode<KeyType> keyChild, APyNode<ValType> valChild) {
        this.leftChild = keyChild;
        this.rightChild = valChild;
    }

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    @Override
    public APyNode<KeyType> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Returns the right child node.
     *
     * @return the right child node
     */
    @Override
    public APyNode<ValType> getRightChild() {
        return this.rightChild;
    }

    /**
     * Generates all valid PyDictObjs within the exhaustive domain; begins by generating
     * all valid keys and values, and then generates all permutations of (key, value)
     * pairs of valid length (as constrained by the exhaustive domain).
     *
     * @return a set of PyDictObjs comprising the exhaustive domain
     */
    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        // Generate all valid keys and values
        Set<KeyType> keyVals = this.leftChild.genExVals();
        Set<ValType> valVals = this.rightChild.genExVals();

        // Generate all permutations of valid (key, value) pairs of valid length
        return this.genDictPerms(keyVals, valVals);
    }

    /**
     * Generates a single valid PyDictObj within the random domain; begins by randomly
     * selecting the size, n (number of (key, value) pairs), and then randomly selects
     * valid (key, value) pairs until there are n unique (key, value) pairs.
     *
     * @return a single PyDictObj selected from the random domain
     */
    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        // Randomly select the size, n
        int size = this.ranDomainChoice().intValue();

        // Randomly select n (key, value) pairs; make sure to continuously monitor the
        // size, as we could generate the same key twice resulting in the size not
        // increasing from one iteration to the next
        Map<KeyType, ValType> map = new HashMap<>();
        while (map.size() < size) {
            KeyType key = this.leftChild.genRandVal();
            ValType val = this.rightChild.genRandVal();
            map.put(key, val);
        }
        return new PyDictObj<>(map);
    }

    /**
     * Generate all permutations of sets of (key, value) pairs where key is an element of
     * keyVals and value is an element of valVals, of size up to and including the input
     * size.
     *
     * @param size    the max size permutation to be generated
     * @param keyVals the set of valid keys that can be contained within the dictionary
     *                being generated
     * @param valVals the set of valid values that can be contained within the dictionary
     *                being generated
     * @return all permutations of valid (key, value) pairs of length up to and including
     * the input size
     */
    private Set<PyDictObj<KeyType, ValType>> genPermsHelper(int size,
                                                            Set<KeyType> keyVals, Set<ValType> valVals) {
        // BASE CASE: size 0 -> return a set containing only the empty dictionary
        if (size == 0) {
            Set<PyDictObj<KeyType, ValType>> perms = new HashSet<>();
            perms.add(new PyDictObj<>(new HashMap<>()));
            return perms;
        }

        // RECURSIVE CASE:
        // Get all permutations that are of length size - 1
        Set<PyDictObj<KeyType, ValType>> oneShorter =
                this.genPermsHelper(size - 1, keyVals, valVals);

        // Iterate over each shorter dictionary, adding each possible single (key,
        // value) pair to it
        Set<PyDictObj<KeyType, ValType>> perms = new HashSet<>(oneShorter);
        for (PyDictObj<KeyType, ValType> dictObj : oneShorter) {
            // Extract the internal HashMap representation
            Map<KeyType, ValType> dict = dictObj.getValue();
            if (dict.size() < size - 1) {
                // For efficiency, let's avoid generating duplicates
                continue;
            }

            // Construct all new dictionaries that result from adding (key, value) to dict
            for (KeyType key : keyVals) {
                for (ValType val : valVals) {
                    // Make sure to clone dict so as not to mutate the original
                    Map<KeyType, ValType> dictClone = new HashMap<>(dict);
                    dictClone.put(key, val);
                    perms.add(new PyDictObj<>(dictClone));
                }
            }
        }
        return perms;
    }

    /**
     * Generates all permutations of sets of (key, value) pairs where key is an element of
     * keyVals and value is an element of valVals, of size up to and including the max
     * value in this.exDomain.
     *
     * @param keyVals the set of valid keys that can be contained within the dictionary
     *                being generated
     * @param valVals the set of valid values that can be contained within the dictionary
     *                being generated
     * @return all permutations of valid (key, value) pairs of length up to and including
     * the max value in this.exDomain
     */
    private Set<PyDictObj<KeyType, ValType>> genDictPerms(Set<KeyType> keyVals,
                                                          Set<ValType> valVals) {
        // Create all dicts up to (and including) the maximum size
        int maxLength = this.exDomainMax();
        Set<PyDictObj<KeyType, ValType>> allPerms =
                this.genPermsHelper(maxLength, keyVals, valVals);

        // Remove dicts of sizes that are not found in this.domain
        Set<PyDictObj<KeyType, ValType>> finalPerms = new HashSet<>();
        for (PyDictObj<KeyType, ValType> dict : allPerms) {
            if (this.exDomain.contains((dict.getValue()).size())) {
                finalPerms.add(dict);
            }
        }
        return finalPerms;
    }
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A class that is used to generate a "base" set of test cases, comprised of the union
 * of a "semi-exhaustive" test set generated within a smaller domain, plus some number of
 * random probes from a larger domain.
 */
public class BaseSetGenerator {

    /**
     * The nodes that will be used to perform generation.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random cases to generate.
     */
    private final int numRand;

    /**
     * The base test set, stored as a field to be accessible to genRandTests().
     */
    private Set<TestCase> baseSet;

    /**
     * Constructor for a BaseSetGenerator, which initializes the fields.
     *
     * @param nodes   the nodes that will be used to perform generation
     * @param numRand the number of random cases to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
        this.baseSet = new HashSet<>();
    }

    /**
     * Generates a the base test set (the union of the semi-exhaustive and random test
     * sets) according to the type and domain specifications in the input list of nodes.
     * Each output test case encapsulates a list of arguments (APyObjs), where the i-th
     * argument is typified by the i-th element in nodes.
     *
     * @return the base test set (as a List, so that we can use indices in the Tester)
     */
    public List<TestCase> genBaseSet() {
        this.baseSet = this.genExTests();
        this.genRandTests();

        // Convert to a list so that we can use indices in testing
        return new ArrayList<>(this.baseSet);
    }

    /**
     * Exbaustively generates a set of all valid test cases within the exhaustive
     * domains stored within the nodes.
     *
     * @return a set of valid test cases according to the given specifications
     */
    public Set<TestCase> genExTests() {
        // For each parameter, generate the set of all possible arguments
        List<Set<? extends APyObj>> possibleArgs = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            Set<? extends APyObj> args = node.genExVals();
            possibleArgs.add(args);
        }

        // Generate all possible combinations of arguments (selecting one valid argument
        // for each parameter)
        List<List<APyObj>> combos = generateArgCombos(possibleArgs, 0);
        Set<TestCase> tests = new HashSet<>();

        // Encapsulate the results within TestCase objects and return
        for (List<APyObj> combo : combos) {
            tests.add(new TestCase(combo));
        }
        return tests;
    }

    /**
     * Randomly generates a list of valid test cases of size numTests, according to the
     * random domains stored within the nodes. Each output test case encapsulates a list
     * of arguments (APyObjs), where the i-th argument is typified by the i-th element in
     * nodes.
     *
     * @return a list of valid test cases, according to the given specifications
     */
    public Set<TestCase> genRandTests() {
        // Get the goal size for the base test set
        int goalSize = this.baseSet.size() + this.numRand;
        Set<TestCase> randSet = new HashSet<>();

        // Randomly generate one test at a time until we've generated enough. Need to
        // continually check the size in case we randomly generate the same test twice
        while (this.baseSet.size() < goalSize) {

            // Randomly generate each argument
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : this.nodes) {
                APyObj arg = node.genRandVal();
                args.add(arg);
            }

            // Wrap arguments in a TestCase object and add to the base set, making sure
            // that it isn't a duplicate of an object in the exhaustive set
            TestCase test = new TestCase(args);
            if (this.baseSet.add(test)) {
                randSet.add(test);
            }
        }

        // Note: randSet is not necessary for any reason other than to allow for better
        // isolation during testing. (I originally declared this as a private void helper,
        // but changed it so that I can give you partial credit if you get random working
        // but not exhaustive.)
        return randSet;
    }

    /**
     * Helper function for generateTest; a recursive algorithm for generating all possible
     * combinations of arguments across multiple parameters. Uses an additional input,
     * index, to keep track of which arguments have already been combined.
     *
     * @param possibleArgs a list of sets, where the i-th set contains all possible
     *                     arguments (as PyObjs) for the i-th parameter
     * @param index        the next index within possibleArgs for which we need to
     *                     generate all possible combinations
     * @return all possible combinations of args, where the i-th element in each sublist
     * within the returned list is an element of the i-th set in possibleArgs
     */
    private static List<List<APyObj>> generateArgCombos(
            List<Set<? extends APyObj>> possibleArgs, int index) {

        // BASE CASE: index is greater than the last index in possibleArgs ->
        // no args remain -> return one empty combination
        if (index == possibleArgs.size()) {
            List<List<APyObj>> combos = new ArrayList<>();
            combos.add(new ArrayList<APyObj>());
            return combos;
        }

        // RECURSIVE CASE: index is within the bounds of possibleArgs ->
        // Get all combinations of the later args
        List<List<APyObj>> laterCombos = generateArgCombos(possibleArgs, index + 1);

        // Get all possible args for the current index
        Set<? extends APyObj> currArgs = possibleArgs.get(index);

        // For every existing combination, add every possible arg in currArs
        List<List<APyObj>> allCombos = new ArrayList<>();
        for (APyObj arg : currArgs) {
            for (List<APyObj> combo : laterCombos) {
                // Make sure to clone so as to not mutate the original
                List<APyObj> comboClone = new ArrayList<>(combo);
                comboClone.add(0, arg);
                allCombos.add(comboClone);
            }
        }
        return allCombos;
    }
}

