/**
 * Stateless class that is a wrapper for a greedy approximation of the set cover
 * algorithm. Running the hitting set algorithm on the results of testing yields a
 * "concise" (approximately minimal) set of test cases that still catches every known
 * (based on the base test set) incorrect implementation.
 */
public class ConciseSetGenerator {

    /**
     * A greedy approximation of the set cover algorithm. Given a set of incorrect
     * implementations (S), a set of test cases (B), and list "mapping" each test case
     * (index i) to the set of implementations (Si) that it caught -- all contained within
     * results --, finds an approximately minimal subset of B (M) such that all of the
     * incorrect implementations are caught by at least one element in M.
     *
     * @param results the results of running all tests in B on all files in S
     * @return M, a set of test cases that is an approximately minimal set covering
     */
    public static Set<TestCase> setCover(TestResults results) {

        // Initialize the structure to return
        HashSet<TestCase> hittingSet = new HashSet<>();

        // We'll be mutating both caseToFiles and wrongSet, so make copies
        List<Set<Integer>> caseToFiles = new ArrayList<>();
        for (Set<Integer> set : results.getCaseToFiles()) {
            caseToFiles.add(new HashSet<>(set));
        }
        Set<Integer> wrongSet = new HashSet<>(results.getWrongSet());

        // Select tests until we've "covered" every program that was initially in the
        // wrong set
        while (wrongSet.size() > 0) {
            int maxFilesCaught = 0;
            int caseOfMaxFiles = -1;

            // Find the test case that covers the most heretofore-uncovered files
            for (int caseIndex = 0; caseIndex < caseToFiles.size(); caseIndex++) {
                Set<Integer> filesCaught = caseToFiles.get(caseIndex);
                if (filesCaught.size() > maxFilesCaught) {
                    maxFilesCaught = filesCaught.size();
                    caseOfMaxFiles = caseIndex;
                }
            }

            // Remove all covered files from the wrongSet
            HashSet<Integer> coveredFiles =
                new HashSet<>(caseToFiles.get(caseOfMaxFiles));
            wrongSet.removeAll(coveredFiles);

            // Update the caseToFiles mapping such that the set of files caught by each
            // test no longer includes the newly-covered files
            for (Set<Integer> filesCaught : caseToFiles) {
                filesCaught.removeAll(coveredFiles);
            }

            // Add the selected test case to the hitting set
            hittingSet.add(results.getTestCase(caseOfMaxFiles));
        }

        // Return the hitting set
        return hittingSet;
    }
}

package main.rice.test;

import main.rice.obj.APyObj;
import java.util.List;

/**
 * A representation of a test case; a wrapper around its arguments, each of which is an
 * APyObj.
 */
public class TestCase {

    /**
     * The list of arguments (Python objects) comprising this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructor for a TestCase; initializes its list of arguments to the input.
     *
     * @param args the list of arguments (Python objects) comprising this test case
     */
    public TestCase(List<APyObj> args) {
        this.args = args;
    }

    /**
     * Returns the list of arguments comprising this test case.
     *
     * @return the list of arguments comprising this test case
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Returns a string representation of this test's arguments.
     *
     * @return a string representation of this test's arguments
     */
    @Override
    public String toString() {
        return this.args.toString();
    }

    /**
     * Compares this test's arguments to the input object's arguments (if it's a TestCase)
     * by value.
     *
     * @param obj the object to compare against
     * @return true if this is equivalent by value to obj; false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        // If obj is not a TestCase, it's not equivalent
        if (!(obj instanceof TestCase other)) {
            return false;
        }

        // Compare the lists of arguments for equality
        return this.args.equals(other.getArgs());
    }

    /**
     * Computes a hash code based on this object's value, such that two objects that are
     * considered equal by .equals() will also have the same hash code.
     *
     * @return the hash code for this object
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }
}

package main.rice.test;

import java.util.List;
import java.util.Set;

/**
 * A representation of the results of running a series of tests on a series of files.
 */
public class TestResults {

    /**
     * All test cases that were executed; each one is a wrapper around a series of
     * PyObjs.
     */
    private final List<TestCase> allCases;

    /**
     * The results of testing, in the form of a list where the i-th element is the set of
     * integers representing the indices of the files that were caught by that i-th test
     * case in allCases.
     */
    private final List<Set<Integer>> caseToFiles;

    /**
     * A set of integers representing the indices of the files that failed one or more
     * tests in allCases.
     */
    private final Set<Integer> wrongSet;

    /**
     * Constructor for a TestResults object; initializes all fields.
     *
     * @param allCases    all test cases that were executed
     * @param caseToFiles a list where the i-th element is a set of integers representing
     *                    the files that were caught by the i-th test case in allCases
     * @param wrongSet    the set of all files that failed one or more tests in allCases
     */
    public TestResults(List<TestCase> allCases, List<Set<Integer>> caseToFiles,
                       Set<Integer> wrongSet) {
        this.allCases = allCases;
        this.caseToFiles = caseToFiles;
        this.wrongSet = wrongSet;
    }

    /**
     * Returns the index-th test case in allCases, if index is within the bounds of
     * allCases; null otherwise.
     *
     * @param index the index of the test case to be returned
     * @return the index-th test case in allTests, if index is valid; null otherwise
     */
    public TestCase getTestCase(int index) {
        // Make sure the index is in bounds; if it's out of bounds, return null
        if (index >= this.allCases.size() || (this.allCases.size() == 0) || (index < 0)) {
            return null;
        }
        return this.allCases.get(index);
    }

    /**
     * Returns the set of files that failed one or more test cases, where files are
     * represented by their indices.
     *
     * @return the set of files that failed one or more test cases
     */
    public Set<Integer> getWrongSet() {
        return this.wrongSet;
    }

    /**
     * Returns the per-case list of files that each test case caught, where files are
     * represented by their indices.
     *
     * @return the per-case list of files that each test case caught
     */
    public List<Set<Integer>> getCaseToFiles() {
        return this.caseToFiles;
    }
}

package main.rice.obj;

/**
 * An abstract class whose instances represent specific Python objects.
 */
public abstract class APyObj {

    /**
     * Returns the underlying (Java) representation of this Python object.
     *
     * @return the underlying (Java) representation of this Python object
     */
    public abstract Object getValue();

    /**
     * Builds and returns a string representation of this object that mirrors the Python
     * string representation.
     *
     * @return a string representation of this object
     */
    @Override
    public abstract String toString();

    /**
     * Compares this to the input object by value.
     *
     * @param obj the object to compare against
     * @return true if this is equivalent by value to obj; false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        // If obj is the wrong type, it's clearly not equivalent
        if (!(obj instanceof APyObj other)) {
            return false;
        }

        // Compare by value
        return this.getValue().equals(other.getValue());
    }

    /**
     * Computes a hash code based on this object's value, such that two objects that are
     * considered equal by .equals() will also have the same hash code.
     *
     * @return the hash code for this object
     */
    @Override
    public int hashCode() {
        return this.getValue().hashCode();
    }
}

package main.rice.obj;

/**
 * A helper class for implementing PyStringObjs; each instance represents a single
 * character in a Python string.
 */
public class PyCharObj extends APyObj {

    /**
     * The value of this PyCharObj.
     */
    private final Character value;

    /**
     * Constructor for a PyCharObj; initializes its value to a string of the input.
     *
     * @param value a character representing the value of this PyCharObj
     */
    public PyCharObj(Character value) {
        this.value = value;
    }

    /**
     * Returns the underlying (Java Character) representation of this PyCharObj.
     *
     * @return the underlying (Java Character) representation of this PyCharObj
     */
    @Override
    public Character getValue() {
        return this.value;
    }

    /**
     * Builds and returns a string representation of this object that mirrors the Python
     * string representation; uses single quotes for compatibility with command-line
     * invocation of Python scripts.
     *
     * @return a string representation of this object
     */
    @Override
    public String toString() {
        return "'" + this.value.toString() + "'";
    }
}
